function applyMirrorTransformDirectly(mirror) {
if (window.__VH360_DEBUG) console.log('VideoHub360 Unified Settings: Applying mirror transformation directly:', mirror);
const videoElements = document.querySelectorAll(
'video, #videohub360-main-video, #vh360-livestream-video, .agora-video-player, [id*="player"], iframe'
);
videoElements.forEach(element => {
element.classList.remove(
'vh360-video-mirrored-horizontal',
'vh360-video-mirrored-vertical',
'vh360-video-mirrored-both'
);
switch (mirror) {
case 'horizontal':
element.classList.add('vh360-video-mirrored-horizontal');
break;
case 'vertical':
element.classList.add('vh360-video-mirrored-vertical');
break;
case 'both':
element.classList.add('vh360-video-mirrored-both');
break;
default:
break;
}
});
if (!document.querySelector('#vh360-mirror-styles')) {
const style = document.createElement('style');
style.id = 'vh360-mirror-styles';
style.textContent = `
.vh360-video-mirrored-horizontal {
transform: scaleX(-1) !important;
}
.vh360-video-mirrored-vertical {
transform: scaleY(-1) !important;
}
.vh360-video-mirrored-both {
transform: scaleX(-1) scaleY(-1) !important;
}
`;
document.head.appendChild(style);
}
}
